function loadDashboard(userId, cb) {
  getUser(userId, (err, user) => {
    if (err) return cb(err);
    getTeams(user.id, (err, teams) => {
      if (err) return cb(err);
      getMetrics(teams[0].id, (err, metrics) => {
        if (err) return cb(err);
        cb(null, { user, teams, metrics });
      });
    });
  });
}

